import{c as r,Q as a,j as t,m as o}from"./chunks/framework.BA1dEi98.js";const i="/librislog/next/screenshots/progress-detail.png",n="/librislog/next/screenshots/progress-log.png",s="/librislog/next/screenshots/progress-entry-edit.png",m=JSON.parse('{"title":"Progress Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/progress.md","filePath":"guide/using-librislog/progress.md","lastUpdated":1780263809000}'),g={name:"guide/using-librislog/progress.md"};function l(d,e,p,h,c,u){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="progress-tracking" tabindex="-1">Progress Tracking <a class="header-anchor" href="#progress-tracking" aria-label="Permalink to &quot;Progress Tracking&quot;">​</a></h1><p>Track your reading progress with page-level granularity. Each update is recorded in a log, giving you a complete history of your reading journey.</p><h2 id="updating-progress" tabindex="-1">Updating Progress <a class="header-anchor" href="#updating-progress" aria-label="Permalink to &quot;Updating Progress&quot;">​</a></h2><p>For books with a page count, open the book detail view and drag the progress slider or type the current page number. Progress is saved automatically when you release the slider or blur the input.</p><p><img src="'+i+'" alt="Progress slider and percentage in the book detail view" loading="lazy"></p><h2 id="progress-log" tabindex="-1">Progress Log <a class="header-anchor" href="#progress-log" aria-label="Permalink to &quot;Progress Log&quot;">​</a></h2><p>Each book maintains a progress log showing the history of page updates:</p><ul><li>Date and time of each entry</li><li>Page number reached</li><li>Actions to edit or delete individual entries</li></ul><p>The log is append-only — each update adds a new entry rather than modifying the previous one.</p><p><img src="'+n+'" alt="Progress log with entry history" loading="lazy"></p><h3 id="editing-an-entry" tabindex="-1">Editing an Entry <a class="header-anchor" href="#editing-an-entry" aria-label="Permalink to &quot;Editing an Entry&quot;">​</a></h3><p>Click the edit button next to a progress log entry to change its date. This is useful if you forgot to log progress on the correct day. The page number cannot be changed — instead, add a new entry with the corrected page.</p><p><img src="'+s+'" alt="Editing a progress entry date" loading="lazy"></p><h3 id="deleting-an-entry" tabindex="-1">Deleting an Entry <a class="header-anchor" href="#deleting-an-entry" aria-label="Permalink to &quot;Deleting an Entry&quot;">​</a></h3><p>Click the delete button next to an entry to remove it from the log. A confirmation prompt appears before deletion.</p><h2 id="reading-percentage" tabindex="-1">Reading Percentage <a class="header-anchor" href="#reading-percentage" aria-label="Permalink to &quot;Reading Percentage&quot;">​</a></h2><p>For books with a page count, the detail view shows your current page, total pages, reading percentage, and a visual progress bar.</p>',17)])])}const b=r(g,[["render",l]]);export{m as __pageData,b as default};
